<?php
namespace Modules\Expenses\Database\Seeders; use Illuminate\Database\Seeder; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Schema;
class MenuSeeder extends Seeder{public function run():void{$target=null;if(Schema::hasTable('admin_menu'))$target='admin_menu';elseif(Schema::hasTable('menus'))$target='menus';elseif(Schema::hasTable('menu_items'))$target='menu_items';if(!$target)return;$exists=$target==='menu_items'?DB::table($target)->where('url','/expenses')->exists():DB::table($target)->where('slug','expenses')->exists();if(!$exists){if($target==='menu_items')DB::table('menu_items')->insert(['title'=>'Expenses','url':'/expenses','icon':'credit_card','sort':70]);else DB::table($target)->insert(['title':'Expenses','slug':'expenses','icon':'credit_card','url':'/expenses','sort':70]);}}}